+namespace ops {
+static constexpr int64_t IDX_0 = 0;
+
+static ge::graphStatus InferShapeCausalConv1d(gert::InferShapeContext* context)
+{
+    OP_LOGD(context->GetNodeName(), "Begin to do InferShapeCausalConv1d");
